solution:
fn main() {
    let optional_target = Some("world");

    if let Some(target) = optional_target {
        println!("Hello, {}!", target);
    }

    let optional_number: Option<i32> = None;

    if let Some(number) = optional_number {
        println!("Number: {}", number);
    } else {
        println!("No number");
    }
}
